1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const PROCESSING_FEE = 5;
11	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
12	const SUBSEQUENT_CONTRACT_MULTIPLIER = 0.85;
13	const ALIKE_BUNDLE_DISCOUNT = 15;
14	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const COMPONENT_TYPES = ["rune", "moonstone"];
18	
19	type Item = { type: string; cursed?: boolean; enchantment?: number };
20	
21	function ceilToWholeGold(amount: number): number {
22	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
23	}
24	
25	function basePremiumFor(itemType: string): number {
26	  return BASE_PREMIUMS[itemType] ?? 0;
27	}
28	
29	function isHighlyEnchanted(item: Item): boolean {
30	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
31	}
32	
33	function itemPremium(item: Item): number {
34	  const base = basePremiumFor(item.type);
35	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
36	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER : 1;
37	  return base * cursedMultiplier * enchantmentMultiplier;
38	}
39	
40	function countOfType(items: Array<Item>, itemType: string): number {
41	  return items.filter((item) => item.type === itemType).length;
42	}
43	
44	function alikeBundleDiscount(items: Array<Item>): number {
45	  const bundleCount = COMPONENT_TYPES.reduce(
46	    (sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3),
47	    0,
48	  );
49	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
50	}
51	
52	function customerMultiplierFor(previousQuotes: number): number {
53	  return previousQuotes >= 1 ? SUBSEQUENT_CONTRACT_MULTIPLIER : INITIAL_ASSESSMENT_MULTIPLIER;
54	}
55	
56	export function quote(input: { items: Array<Item>; previousQuotes?: number }): number {
57	  const itemPremiumSum = input.items.reduce((sum, item) => sum + itemPremium(item), 0);
58	  const itemsTotal = itemPremiumSum - alikeBundleDiscount(input.items);
59	  const customerMultiplier = customerMultiplierFor(input.previousQuotes ?? 0);
60	  const total = itemsTotal * customerMultiplier + PROCESSING_FEE;
61	  return ceilToWholeGold(total);
62	}
63	
64	export function claim(_input: unknown): number {
65	  return undefined as unknown as number;
66	}
